package testutils

import (
	"time"

	"kisanlink-erp/internal/database/models"
)

// ========================================
// Test Data Factory Functions
// ========================================
// These functions create test data structures without database operations
// Following the e-commerce pattern for simple, fast unit tests

// ========================================
// Warehouse Fixtures
// ========================================

func FixtureWarehouse(name string) *models.Warehouse {
	warehouse := models.NewWarehouse(name, nil)
	// Note: ID is auto-generated by BaseModel - don't set it to allow multiple warehouses
	return warehouse
}

func FixtureWarehouseWithID(id, name string) *models.Warehouse {
	warehouse := models.NewWarehouse(name, nil)
	warehouse.ID = id
	return warehouse
}

func FixtureWarehouseWithAddress(name, addressType, pincode string) *models.Warehouse {
	address := &models.CreateAddressRequest{
		Type:      addressType,
		Pincode:   &pincode,
		IsPrimary: true,
	}
	warehouse := models.NewWarehouseWithAddress(name, address)
	// Note: ID is auto-generated by BaseModel - don't set it to allow multiple warehouses
	return warehouse
}

