// ========================================
// ProductVariant Fixtures
// ========================================

func FixtureProductVariant(productID, variantName string) *models.ProductVariant {
	variant := models.NewProductVariant(productID, variantName, "1", "1kg")
	// Note: ID and SKU are auto-generated - don't hardcode to allow multiple variants
	// Generate unique SKU based on variant name to avoid conflicts
	sku := "SKU-" + variantName
	variant.SKU = &sku
	return variant
}

func FixtureProductVariantWithID(id, productID, variantName string) *models.ProductVariant {
	variant := models.NewProductVariant(productID, variantName, "1", "1kg")
	variant.ID = id
	sku := "SKU-" + id
	variant.SKU = &sku
	return variant
}

func FixtureProductVariantWithSKU(productID, variantName, sku string) *models.ProductVariant {
	variant := FixtureProductVariant(productID, variantName)
	variant.SKU = &sku
	return variant
}

