// ========================================

func FixturePurchaseOrder(collaboratorID, warehouseID string, totalAmount float64) *models.PurchaseOrder {
	poNumber := "PO-TEST-001"
	po := models.NewPurchaseOrder(poNumber, collaboratorID, warehouseID, time.Now(), time.Now().AddDate(0, 0, 7))
	po.ID = "PO-TEST-001"
	po.TotalAmount = totalAmount
	po.Status = "placed"
	return po
}

func FixturePurchaseOrderWithID(id, poNumber, collaboratorID, warehouseID string, totalAmount float64) *models.PurchaseOrder {
	po := models.NewPurchaseOrder(poNumber, collaboratorID, warehouseID, time.Now(), time.Now().AddDate(0, 0, 7))
	po.ID = id
	po.TotalAmount = totalAmount
	po.Status = "placed"
	return po
}

func FixturePurchaseOrderWithStatus(collaboratorID, warehouseID, status string, totalAmount float64) *models.PurchaseOrder {
	po := FixturePurchaseOrder(collaboratorID, warehouseID, totalAmount)
	po.Status = status
	return po
}

func FixturePurchaseOrderWithItems(collaboratorID, warehouseID string, items []models.PurchaseOrderItem) *models.PurchaseOrder {
	po := FixturePurchaseOrder(collaboratorID, warehouseID, 0)
	po.Items = items

	// Calculate total amount from items
	totalAmount := 0.0
	for _, item := range items {
		totalAmount += item.LineTotal
	}
	po.TotalAmount = totalAmount

	return po
}

