func FixtureDiscount(name, code string, discountType models.DiscountType, value float64) *models.Discount {
	desc := new(string)
	*desc = "Test discount"
	startDate := time.Now()
	endDate := time.Now().AddDate(0, 1, 0) // 1 month from now
	discount := models.NewDiscount(name, code, desc, discountType, value, startDate, endDate)
	discount.ID = "DISCOUNT-TEST-001"
	return discount
}

func FixtureDiscountWithID(id, name, code string, discountType models.DiscountType, value float64) *models.Discount {
	discount := FixtureDiscount(name, code, discountType, value)
	discount.ID = id
	return discount
}

func FixtureDiscountFlat(name, code string, value float64) *models.Discount {
	return FixtureDiscount(name, code, models.DiscountTypeFlat, value)
}

func FixtureDiscountPercentage(name, code string, value float64) *models.Discount {
	return FixtureDiscount(name, code, models.DiscountTypePercentage, value)
}

func FixtureDiscountWithDates(name, code string, discountType models.DiscountType, value float64, startDate, endDate time.Time) *models.Discount {
	desc := new(string)
	*desc = "Test discount"
	discount := models.NewDiscount(name, code, desc, discountType, value, startDate, endDate)
	discount.ID = "DISCOUNT-TEST-001"
	return discount
}

func FixtureDiscountWithUsageLimit(name, code string, discountType models.DiscountType, value float64, usageLimit int) *models.Discount {
	discount := FixtureDiscount(name, code, discountType, value)
	limit := usageLimit
	discount.UsageLimit = &limit
	return discount
}

func FixtureDiscountInactive(name, code string, discountType models.DiscountType, value float64) *models.Discount {
	discount := FixtureDiscount(name, code, discountType, value)
	discount.IsActive = false
	return discount
}

func FixtureDiscountExpired(name, code string, discountType models.DiscountType, value float64) *models.Discount {
	desc := new(string)
	*desc = "Test discount"
	startDate := time.Now().AddDate(0, -2, 0) // 2 months ago
	endDate := time.Now().AddDate(0, -1, 0)   // 1 month ago (expired)
	discount := models.NewDiscount(name, code, desc, discountType, value, startDate, endDate)
	discount.ID = "DISCOUNT-TEST-001"
	return discount
}

